function solve(nums, k) {
    let n = nums.length;
    let prefix_sums = [0];
    for (let num of nums) {
        prefix_sums.push(prefix_sums[prefix_sums.length - 1] + num);
    }
    let total = prefix_sums[prefix_sums.length - 1];
    let mod_map = new Map();
    mod_map.set(0, 0);
    let dp_prev = 0;
    for (let i = 1; i <= n; i++) {
        let current_sum = prefix_sums[i];
        let current_mod = current_sum % k;
        let max_prev = mod_map.get(current_mod) || -Infinity;
        let candidate = max_prev + current_sum;
        let current_dp = Math.max(dp_prev, candidate);
        let current_value = current_dp - current_sum;
        if (mod_map.has(current_mod)) {
            if (current_value > mod_map.get(current_mod)) {
                mod_map.set(current_mod, current_value);
            }
        } else {
            mod_map.set(current_mod, current_value);
        }
        dp_prev = current_dp;
    }
    return total - dp_prev;
}
